const express = require('express');
const { MongoClient } = require('mongodb');

const app = express();
const port = 3000;

// MongoDB connection URI and Database Name
const mongoUri = 'mongodb://localhost:27017'; // Replace with your MongoDB URI if different
const dbName = 'yourDatabaseName'; // Replace with your database name
const collectionName = 'yourCollectionName'; // Replace with your collection name

let db;

// Connect to MongoDB once when the server starts
MongoClient.connect(mongoUri)
  .then(client => {
    db = client.db(dbName);
    console.log(`Connected to MongoDB: ${dbName}`);
  })
  .catch(err => {
    console.error('Failed to connect to MongoDB', err);
    process.exit(1); // Exit the process if MongoDB connection fails
  });

// Middleware to parse JSON request bodies
app.use(express.json());

// API endpoint to query MongoDB
app.post('/query', async (req, res) => {
  const filter = req.body; // Accept the entire request body as the filter object

  if (!filter || typeof filter !== 'object') {
    return res.status(400).json({ error: 'Invalid filter provided. Filter must be a JSON object.' });
  }

  try {
    const collection = db.collection(collectionName);
    const result = await collection.find(filter).toArray();
    res.json(result);
  } catch (error) {
    console.error('Error executing MongoDB query:', error);
    res.status(500).json({ error: 'Failed to execute query', details: error.message });
  }
});

// Start the Express server
app.listen(port, () => {
  console.log(`Query service listening at http://localhost:${port}`);
});